export function createChatRunRegistry(gateway: GatewayServer) {

  async function handleChatSend(
    sessionEntry: SessionEntry,
    message: InboundMessage,
  ) {
    sessionEntry.transcript.push({
      role: 'user',
      content: message.text,
      timestamp: Date.now(),
    })

    const agentRpc = gateway.acp.getClient(sessionEntry.agentId)
    const stream = await agentRpc.call('chat.send', {
      sessionId: sessionEntry.sessionKey,
      messages: sessionEntry.transcript,
      tools: sessionEntry.metadata.enabledTools,
      model: sessionEntry.metadata.model,
    })

    for await (const chunk of stream) {
      if (chunk.type === 'text') {
        gateway.broadcast('chat.stream', { text: chunk.text })
      } else if (chunk.type === 'tool_use') {
        const result = await executeTool(chunk.tool, chunk.input)
        agentRpc.sendToolResult(chunk.id, result)
      }
    }
    await saveSession(sessionEntry)
  }

  return { handleChatSend }
}","language":"typescript"},"narration":"The gateway server accepts WebSocket connections from channels, the CLI, and native apps. The streaming loop handles text and tool calls differently. Text streams in real time; tool calls get executed on the gateway and results feed back."},{"name":"Agent RPC Rapids","subtitle":"Talking to the AI","concept":"Gateway Control Plane","landmarkType":"river","code":{"file":"src/acp/client.ts","content":"// src/acp/client.ts (simplified)
export function createAcpClient(agentId: string, wsUrl: string) {
  const ws = new WebSocket(wsUrl)

  async function* call(
    method: string,
    params: ChatSendParams,
  ): AsyncGenerator<AgentChunk> {
    const requestId = crypto.randomUUID()

    ws.send(JSON.stringify({
      jsonrpc: '2.0',
      id: requestId,
      method,
      params,
    }))

    while (true) {
      const msg = await nextMessage(ws, requestId)
      if (msg.type === 'done') break
      yield msg
    }
  }

  function sendToolResult(toolCallId: string, result: ToolResult) {
    ws.send(JSON.stringify({
      jsonrpc: '2.0',
      method: 'tool.result',
      params: { toolCallId, result },
    }))
  }

  return { call, sendToolResult }
}","language":"typescript"},"narration":"Now we cross the RPC Rapids. The gateway and agent communicate over JSON-RPC. The agent decides what to do, but the gateway controls what actually happens on your machine. Security through architecture."},{"name":"Tool Execution Gorge","subtitle":"Running Commands on the Host","concept":"Gateway Control Plane","landmarkType":"forest","code":{"file":"src/agents/bash-tools.exec.ts","content":"// src/agents/bash-tools.exec.ts (simplified)
export async function executeBashTool(
  input: { command: string },
  context: ToolContext,
): Promise<ToolResult> {
  const { command } = input
  const { sessionEntry, securityPolicy } = context

  if (!securityPolicy.allowBash) {
    return { error: 'Bash execution not permitted' }
  }

  const pty = spawn('bash', ['-c', command], {
    cwd: sessionEntry.metadata.workingDir,
    env: { ...process.env, ...sessionEntry.metadata.env },
    timeout: 120_000,
  })

  let stdout = ''
  pty.onData(data => { stdout += data })
  const exitCode = await pty.wait()

  return {
    stdout: stdout.slice(0, 100_000),
    exitCode,
  }
}","language":"typescript"},"narration":"Deep in Tool Execution Gorge, the agent's intentions become real actions. Security check first, then a real PTY with a two-minute timeout. Bash is just one tool — same pattern for browser control, canvas, and device actions."},{"name":"Response Delivery Frontier","subtitle":"Back Through the Channel","concept":"Channel Plugins","landmarkType":"town","code":{"file":"src/gateway/server-channels.ts","content":"// src/gateway/server-channels.ts (simplified)
export function createChannelManager(gateway: GatewayServer) {

  async function deliverResponse(
    sessionEntry: SessionEntry,
    response: AgentResponse,
  ) {
    const { channel, peer, accountId } = sessionEntry.routing
    const plugin = gateway.channels.get(channel)

    const formatted = formatForChannel(channel, response.text, {
      maxLength: getChannelLimit(channel),
    })

    for (const chunk of formatted) {
      await plugin.send({ accountId, peer, text: chunk })
    }

    sessionEntry.transcript.push({
      role: 'assistant',
      content: response.text,
      timestamp: Date.now(),
    })
    await saveSession(sessionEntry)

    gateway.broadcast('chat.response', { text: response.text })
  }

