322→  ctx.fillStyle = '#885500';
323→  ctx.fillRect(Math.floor(wx + 2), Math.floor(wy - 8), 24, 1);
324→  ctx.fillRect(Math.floor(wx + 2), Math.floor(wy + 1), 24, 1);
325→  // Canvas cover (white curved top)
326→  ctx.fillStyle = '#FFFFFF';
327→  ctx.beginPath();
328→  ctx.moveTo(Math.floor(wx + 3), Math.floor(wy - 8));
329→  ctx.quadraticCurveTo(Math.floor(wx + 14), Math.floor(wy - 22), Math.floor(wx + 25), Math.floor(wy - 8));
330→  ctx.closePath();
331→  ctx.fill();
332→  // Canvas cover outline
333→  ctx.strokeStyle = '#AAAAAA';
334→  ctx.lineWidth = 1;
335→  ctx.beginPath();
336→  ctx.moveTo(Math.floor(wx + 3), Math.floor(wy - 8));
337→  ctx.quadraticCurveTo(Math.floor(wx + 14), Math.floor(wy - 22), Math.floor(wx + 25), Math.floor(wy - 8));
338→  ctx.stroke();
339→  // Canvas ribs
