332→  // Canvas cover outline
333→  ctx.strokeStyle = '#AAAAAA';
334→  ctx.lineWidth = 1;
335→  ctx.beginPath();
336→  ctx.moveTo(Math.floor(wx + 3), Math.floor(wy - 8));
337→  ctx.quadraticCurveTo(Math.floor(wx + 14), Math.floor(wy - 22), Math.floor(wx + 25), Math.floor(wy - 8));
338→  ctx.stroke();
339→  // Canvas ribs
340→  ctx.strokeStyle = '#AAAAAA';
341→  for (let ri = 0; ri < 3; ri++) {
342→    const rx = wx + 8 + ri * 5;
343→    ctx.beginPath();
344→    ctx.moveTo(Math.floor(rx), Math.floor(wy - 8));
345→    ctx.lineTo(Math.floor(rx), Math.floor(wy - 14 - ri % 2 * 2));
346→    ctx.stroke();
347→  }
348→  // Wheels
349→  const wheelR = 5;
