714→function drawDeathScene(time) {
715→  var t = (time || 0) * 0.001;
716→  var G = '#33FF33'; // Apple II green
717→  var GD = '#1a8a1a'; // darker green for details
718→
719→  // Black background
720→  ctx.fillStyle = '#000000';
721→  ctx.fillRect(0, 0, W, H);
722→
723→  // Ground line
724→  ctx.fillStyle = GD;
725→  ctx.fillRect(0, 148, W, 1);
726→
727→  // --- OX (left side) ---
728→  var ox = 100, oy = 128;
729→  // Body
730→  ctx.fillStyle = G;
731→  ctx.fillRect(ox, oy, 24, 14);
732→  // Head
733→  ctx.fillRect(ox - 10, oy - 2, 12, 10);
734→  // Horns
735→  ctx.fillRect(ox - 12, oy - 6, 3, 5);
736→  ctx.fillRect(ox - 4, oy - 6, 3, 5);
737→  // Snout
738→  ctx.fillStyle = GD;
739→  ctx.fillRect(ox - 10, oy + 4, 6, 3);
740→  // Eye
741→  ctx.fillStyle = '#000';
742→  ctx.fillRect(ox - 7, oy, 2, 2);
743→  // Legs
744→  ctx.fillStyle = G;
745→  ctx.fillRect(ox + 2, oy + 14, 4, 8);
746→  ctx.fillRect(ox + 10, oy + 14, 4, 8);
747→  ctx.fillRect(ox + 16, oy + 14, 4, 8);
748→  // Tail
749→  ctx.fillRect(ox + 24, oy + 2, 6, 2);
750→  ctx.fillRect(ox + 29, oy, 2, 4);
751→
752→  // --- HITCH ---
753→  ctx.fillStyle = G;
754→  ctx.fillRect(ox + 28, oy + 8, 14, 2);
755→
756→  // --- WAGON ---
757→  var wx = 142, wy = 108;
758→  // Wagon bed
759→  ctx.fillStyle = G;
760→  ctx.fillRect(wx, wy + 20, 50, 16);
761→  // Bed slats (dark lines)
762→  ctx.fillStyle = GD;
763→  ctx.fillRect(wx, wy + 24, 50, 1);
764→  ctx.fillRect(wx, wy + 28, 50, 1);
765→  ctx.fillRect(wx, wy + 32, 50, 1);
766→  // Side rails
767→  ctx.fillStyle = G;
768→  ctx.fillRect(wx, wy + 18, 2, 18);
769→  ctx.fillRect(wx + 48, wy + 18, 2, 18);
770→
771→  // Canvas cover (the bonnet)
772→  ctx.fillStyle = G;
773→  // Left arch
774→  ctx.fillRect(wx + 4, wy + 4, 2, 16);
775→  // Right arch
776→  ctx.fillRect(wx + 44, wy + 4, 2, 16);
777→  // Top cover
778→  ctx.fillRect(wx + 4, wy + 2, 42, 4);
779→  // Cover fill
780→  ctx.fillRect(wx + 6, wy + 6, 38, 12);
781→  // Cover shading
782→  ctx.fillStyle = GD;
783→  ctx.fillRect(wx + 8, wy + 8, 34, 2);
784→  ctx.fillRect(wx + 8, wy + 12, 34, 2);
785→  ctx.fillRect(wx + 8, wy + 16, 34, 1);
786→
787→  // Wheels
788→  var wheelR = 8;
789→  var wheels = [wx + 8, wx + 42];
790→  var wa = t * 0.5; // slow rotation
791→  ctx.strokeStyle = G;
792→  ctx.lineWidth = 1.5;
793→  for (var wi = 0; wi < wheels.length; wi++) {
794→    var cx = wheels[wi], cy = wy + 38;
795→    // Rim
796→    ctx.beginPath();
797→    ctx.arc(cx, cy, wheelR, 0, Math.PI * 2);
798→    ctx.stroke();
799→    // Spokes
800→    for (var sp = 0; sp < 6; sp++) {
801→      var angle = wa + sp * Math.PI / 3;
802→      ctx.beginPath();
803→      ctx.moveTo(cx, cy);
804→      ctx.lineTo(cx + Math.cos(angle) * wheelR, cy + Math.sin(angle) * wheelR);
805→      ctx.stroke();
806→    }
807→    // Hub
808→    ctx.fillStyle = G;
809→    ctx.beginPath();
810→    ctx.arc(cx, cy, 2, 0, Math.PI * 2);
811→    ctx.fill();
812→  }
813→  ctx.lineWidth = 1;
814→
815→  // Subtle scanline effect
816→  ctx.fillStyle = 'rgba(0,0,0,0.08)';
817→  for (var sl = 0; sl < H; sl += 3) {
818→    ctx.fillRect(0, sl, W, 1);
819→  }
820→
821→  // Subtle green glow/vignette
822→  var grd = ctx.createRadialGradient(W/2, H/2, 40, W/2, H/2, W * 0.7);
823→  grd.addColorStop(0, 'rgba(0,0,0,0)');
824→  grd.addColorStop(1, 'rgba(0,0,0,0.4)');
825→  ctx.fillStyle = grd;
826→  ctx.fillRect(0, 0, W, H);
827→}
