 967→  { note: 'C4', dur: 1 }, { note: 'E4', dur: 1 }, { note: 'G4', dur: 1 }, { note: 'E4', dur: 1 },
 968→  { note: 'D4', dur: 1 }, { note: 'C4', dur: 3 }
 969→];
