 982→function initAudio() {
 983→  if (audioCtx) return;
 984→  try {
 985→    audioCtx = new (window.AudioContext || window.webkitAudioContext)();
 986→    masterGain = audioCtx.createGain();
 987→    masterGain.gain.value = 1.0;
 988→    masterGain.connect(audioCtx.destination);
 989→    musicInitialized = true;
 990→  } catch (e) {
 991→    console.warn('Web Audio not available:', e);
 992→  }
 993→}
 994→
 995→function playNote(freq, startTime, duration, type, gainVal) {
 996→  if (!audioCtx || freq === 0) return;
 997→  const osc = audioCtx.createOscillator();
 998→  const gain = audioCtx.createGain();
 999→  osc.type = type;
1000→  osc.frequency.setValueAtTime(freq, startTime);
1001→  // Envelope: attack then decay
1002→  gain.gain.setValueAtTime(0.001, startTime);
1003→  gain.gain.linearRampToValueAtTime(gainVal, startTime + 0.02);
1004→  gain.gain.setValueAtTime(gainVal, startTime + duration * 0.75);
1005→  gain.gain.linearRampToValueAtTime(0.001, startTime + duration * 0.95);
1006→  osc.connect(gain);
1007→  gain.connect(masterGain || audioCtx.destination);
1008→  osc.start(startTime);
1009→  osc.stop(startTime + duration);
1010→}
1011→
1012→function scheduleLoop() {
1013→  if (!musicPlaying || !audioCtx) return;
1014→  const bpm = 110;
1015→  const quarterDur = 60 / bpm;
1016→  const now = audioCtx.currentTime;
1017→
1018→  // Schedule melody
1019→  let t = now + 0.05;
1020→  for (const note of melody) {
1021→    const dur = note.dur * quarterDur;
1022→    if (note.note !== 'REST') {
1023→      playNote(NOTE_FREQ[note.note], t, dur, 'square', 0.06);
1024→    }
1025→    t += dur;
1026→  }
1027→
1028→  // Schedule bass
1029→  let tb = now + 0.05;
1030→  for (const note of bassLine) {
1031→    const dur = note.dur * quarterDur;
1032→    playNote(NOTE_FREQ[note.note], tb, dur, 'triangle', 0.08);
1033→    tb += dur;
1034→  }
1035→
1036→  // Total loop duration in beats: melody has 32 quarter beats = 32 * quarterDur
1037→  const totalBeats = 32;
1038→  const loopDurationMs = totalBeats * quarterDur * 1000;
1039→
1040→  musicScheduleTimer = setTimeout(scheduleLoop, loopDurationMs - 200);
1041→}
1042→
1043→function startMusic() {
1044→  if (!musicInitialized) initAudio();
1045→  if (!audioCtx) return;
1046→  if (audioCtx.state === 'suspended') audioCtx.resume();
1047→  if (masterGain) masterGain.gain.setValueAtTime(1.0, audioCtx.currentTime);
1048→  musicPlaying = true;
1049→  scheduleLoop();
1050→  updateMusicIndicator();
1051→}
