1056→    clearTimeout(musicScheduleTimer);
1057→    musicScheduleTimer = null;
1058→  }
1059→  if (masterGain) masterGain.gain.setValueAtTime(0, audioCtx.currentTime);
1060→  updateMusicIndicator();
1061→}
