1083→const TS_KEYWORDS = new Set([
1084→  'import', 'export', 'from', 'const', 'let', 'var', 'function', 'async',
1085→  'await', 'return', 'if', 'else', 'for', 'while', 'new', 'typeof', 'instanceof',
1086→  'interface', 'type', 'class', 'extends', 'implements', 'try', 'catch', 'throw',
1087→  'default', 'switch', 'case', 'break', 'continue', 'true', 'false', 'null',
1088→  'undefined', 'void', 'of', 'in'
1089→]);
