1091→function escHtml(s) {
1092→  return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
1093→}
1094→
1095→function highlightCode(code) {
1096→  return code.split('\n').map(function(line) {
1097→    if (line.trim().startsWith('//')) {
1098→      return '<span style="color:#555555">' + escHtml(line) + '</span>';
1099→    }
1100→    var result = '';
1101→    var i = 0;
1102→    while (i < line.length) {
1103→      // String literal
1104→      if (line[i] === "'" || line[i] === '"' || line[i] === '`') {
1105→        var quote = line[i];
1106→        var end = i + 1;
1107→        while (end < line.length && line[end] !== quote) {
1108→          if (line[end] === '\\') end++;
1109→          end++;
1110→        }
1111→        end = Math.min(end + 1, line.length);
1112→        result += '<span style="color:#FFFF55">' + escHtml(line.substring(i, end)) + '</span>';
1113→        i = end;
1114→        continue;
1115→      }
1116→      // Inline comment
1117→      if (line[i] === '/' && i + 1 < line.length && line[i + 1] === '/') {
1118→        result += '<span style="color:#555555">' + escHtml(line.substring(i)) + '</span>';
1119→        break;
1120→      }
1121→      // Number
1122→      if (/\d/.test(line[i]) && (i === 0 || !/\w/.test(line[i - 1]))) {
1123→        var end2 = i;
1124→        while (end2 < line.length && /[\d._]/.test(line[end2])) end2++;
1125→        result += '<span style="color:#FF55FF">' + escHtml(line.substring(i, end2)) + '</span>';
1126→        i = end2;
1127→        continue;
1128→      }
1129→      // Identifier or keyword
1130→      if (/[a-zA-Z_$]/.test(line[i])) {
1131→        var end3 = i;
1132→        while (end3 < line.length && /[\w$]/.test(line[end3])) end3++;
1133→        var word = line.substring(i, end3);
1134→        if (TS_KEYWORDS.has(word)) {
1135→          result += '<span style="color:#55FFFF">' + escHtml(word) + '</span>';
1136→        } else {
1137→          result += '<span style="color:#55FF55">' + escHtml(word) + '</span>';
1138→        }
1139→        i = end3;
1140→        continue;
1141→      }
1142→      // Punctuation / operators
1143→      result += '<span style="color:#AAAAAA">' + escHtml(line[i]) + '</span>';
1144→      i++;
1145→    }
1146→    return result;
1147→  }).join('\n');
1148→}
