1884→// =====================================================================
1885→// ANIMATION LOOP + TECH DEBT DRAIN
1886→// =====================================================================
1887→var lastTime = 0;
1888→var drainAccumulator = 0;
1889→var DRAIN_INTERVAL = 3000; // drain 1 HP every 3 seconds
1890→var techDebtDeath = false;
1891→
1892→function gameLoop(timestamp) {
1893→  var dt = timestamp - lastTime;
1894→  lastTime = timestamp;
1895→
1896→  // Clamp dt to avoid huge jumps
1897→  if (dt > 100) dt = 16;
1898→
1899→  if (gameState === STATES.TRAVEL) {
1900→    scrollX += dt * 0.03;
1901→    wagonWheelAngle += dt * 0.004;
1902→  } else if (gameState === STATES.TITLE) {
1903→    scrollX += dt * 0.01;
1904→  } else {
1905→    // Gentle idle scroll
1906→    scrollX += dt * 0.002;
1907→  }
1908→
1909→  // Tech debt drain: HP ticks down during active gameplay (disabled for Ralph Wiggum)
1910→  var isForgiving = PROFESSIONS[difficulty] && PROFESSIONS[difficulty].forgiving;
1911→  var isActive = gameState === STATES.STOP || gameState === STATES.EVENT || gameState === STATES.RIVER;
1912→  if (isActive && !deathPending && !isForgiving) {
1913→    drainAccumulator += dt;
1914→    while (drainAccumulator >= DRAIN_INTERVAL) {
1915→      drainAccumulator -= DRAIN_INTERVAL;
1916→      health--;
1917→      renderStatusBar();
1918→      if (health <= 0) {
1919→        techDebtDeath = true;
1920→        enterDeath();
1921→        break;
1922→      }
1923→    }
1924→  }
1925→
1926→  renderCanvas(timestamp);
1927→  animFrame = requestAnimationFrame(gameLoop);
1928→}
