1583→  var prof = PROFESSIONS[difficulty];
1584→  var forgiving = prof && prof.forgiving;
1585→  var origIdx = shuffledIndices[displayIdx];
1586→  var choice = event.choices[origIdx];
1587→  var isRiver = event.type === 'river';
1588→
1589→  if (forgiving && !choice.correct) {
