1597→    for (var ni = 0; ni < shuffledIndices.length; ni++) {
1598→      var nextIdx = (displayIdx + 1 + ni) % shuffledIndices.length;
1599→      if (!(eventHinted && dimmedChoice === nextIdx) && !items[nextIdx].classList.contains('choice-dimmed')) {
1600→        selectedEventChoice = nextIdx;
