1623→    var concept = event.concept;
1624→    var memberIdx = -1;
1625→    for (var mi = 0; mi < TRAIL_DATA.partyMembers.length; mi++) {
1626→      if (TRAIL_DATA.partyMembers[mi].name === concept) { memberIdx = mi; break; }
1627→    }
1628→    if (memberIdx >= 0 && partyHealth[memberIdx] > 0) {
1629→      partyHealth[memberIdx]--;
1630→    }
1631→  }
