1690→function advanceFromEvent() {
1691→  currentEventIndex++;
1692→  if (currentEventIndex < pendingEvents.length) {
1693→    if (checkDeath()) return;
1694→    showNextEvent();
1695→  } else {
1696→    if (checkDeath()) return;
1697→    enterStop();
1698→  }
1699→}
1700→
1701→function enterStop() {
1702→  gameState = STATES.STOP;
1703→  showRiver = false;
1704→  selectedStopChoice = 0;
1705→
1706→  var stop = TRAIL_DATA.stops[currentStop];
1707→  if (stop && stop.landmarkType === 'river') {
1708→    showRiver = true;
1709→  }
1710→
1711→  renderStopScreen();
1712→  renderStatusBar();
1713→}
1714→
1715→function handleStopChoice(choice) {
1716→  if (choice === 2) {
1717→    var codeBox = textPanel.querySelector('.code-box');
1718→    if (codeBox) {
1719→      codeBox.style.maxHeight = '280px';
1720→      codeBox.scrollIntoView({ behavior: 'smooth' });
1721→    }
1722→    return;
1723→  }
1724→
1725→  currentStop++;
1726→  if (currentStop >= TRAIL_DATA.stops.length) {
1727→    enterWin();
1728→  } else {
1729→    enterTravel();
1730→  }
1731→}
1732→
1733→function enterDeath() {
1734→  gameState = STATES.DEATH;
1735→  showRiver = false;
1736→  renderDeathScreen();
1737→  renderStatusBar();
1738→}
1739→

1740→function enterWin() {
1741→  gameState = STATES.WIN;
1742→  showRiver = false;
1743→  renderWinScreen();
1744→  renderStatusBar();
1745→}
1746→
1747→// =====================================================================
1748→// INPUT HANDLING
1749→// =====================================================================
1750→function ensureAudio() {
1751→  if (!musicInitialized) {
1752→    initAudio();
1753→    startMusic();
1754→  }
1755→}
1756→
1757→document.addEventListener('keydown', function(e) {
1758→  var key = e.key;
1759→
1760→  // Music toggle always works
1761→  if (key === 'm' || key === 'M') {
1762→    if (!musicInitialized) initAudio();
1763→    toggleMusic();
1764→    return;
1765→  }
1766→
1767→  // Start audio on first interaction
1768→  if (!musicInitialized) ensureAudio();
1769→
1770→  switch (gameState) {
1771→    case STATES.TITLE:
1772→      if (key === ' ' || key === 'Enter') {
1773→        e.preventDefault();
1774→        gameState = STATES.SETUP;
1775→        renderSetupScreen();
1776→        renderStatusBar();
1777→      }
1778→      break;
1779→
1780→    case STATES.SETUP:
1781→      if (key === 'ArrowDown' || key === 'ArrowRight') {
1782→        e.preventDefault();
1783→        selectDifficulty((selectedDifficulty + 1) % PROFESSIONS.length);
1784→      } else if (key === 'ArrowUp' || key === 'ArrowLeft') {
1785→        e.preventDefault();
1786→        selectDifficulty((selectedDifficulty - 1 + PROFESSIONS.length) % PROFESSIONS.length);
1787→      } else if (key === '1') selectDifficulty(0);
1788→      else if (key === '2') selectDifficulty(1);
1789→      else if (key === '3') selectDifficulty(2);
1790→      else if (key === '4') selectDifficulty(3);
1791→      else if (key === 'Enter' || key === ' ') {
1792→        e.preventDefault();
1793→        startGame();
1794→      }
1795→      break;
1796→
1797→    case STATES.TRAVEL:
1798→      if (key === ' ' || key === 'Enter') {
1799→        e.preventDefault();
1800→        advanceFromTravel();
1801→      }
1802→      break;
1803→
1804→    case STATES.STOP:
1805→      if (key === 'ArrowLeft' || key === 'ArrowRight') {
1806→        e.preventDefault();
1807→        selectedStopChoice = (key === 'ArrowLeft') ? 0 : 1;
1808→        updateStopHighlight();
1809→      } else if (key === 'ArrowUp' || key === 'ArrowDown') {
1810→        e.preventDefault();
1811→        selectedStopChoice = selectedStopChoice === 0 ? 1 : 0;
1812→        updateStopHighlight();
1813→      } else if (key === 'Enter' || key === ' ') {
1814→        e.preventDefault();
1815→        handleStopChoice(selectedStopChoice + 1);
1816→      } else if (key === '1') {
1817→        handleStopChoice(1);
1818→      } else if (key === '2') {
1819→        handleStopChoice(2);
1820→      }
1821→      break;
1822→
1823→    case STATES.EVENT:
1824→    case STATES.RIVER:
1825→      if (!eventAnswered) {
1826→        var ev = pendingEvents[currentEventIndex];
1827→        if (ev && ev.choices.length > 0) {
1828→          var numChoices = ev.choices.length;
1829→          if (key === 'ArrowDown' || key === 'ArrowRight') {
1830→            e.preventDefault();
1831→            selectedEventChoice = (selectedEventChoice + 1) % numChoices;
1832→            // Skip dimmed choice
1833→            if (eventHinted && dimmedChoice === selectedEventChoice) selectedEventChoice = (selectedEventChoice + 1) % numChoices;
1834→            updateChoiceHighlight();
1835→          } else if (key === 'ArrowUp' || key === 'ArrowLeft') {
1836→            e.preventDefault();
1837→            selectedEventChoice = (selectedEventChoice - 1 + numChoices) % numChoices;
1838→            if (eventHinted && dimmedChoice === selectedEventChoice) selectedEventChoice = (selectedEventChoice - 1 + numChoices) % numChoices;
1839→            updateChoiceHighlight();
1840→          } else if (key === 'Enter' || key === ' ') {
1841→            e.preventDefault();
1842→            if (!(eventHinted && dimmedChoice === selectedEventChoice)) {
1843→              handleEventChoice(selectedEventChoice);
1844→            }
1845→          } else if (key === '1' || key === 'a' || key === 'A') handleEventChoice(0);
1846→          else if (key === '2' || key === 'b' || key === 'B') handleEventChoice(1);
1847→          else if (key === '3' || key === 'c' || key === 'C') handleEventChoice(2);
1848→          else if (key === 'h' || key === 'H') handleEventHint();
1849→        }
1850→        // Fortune: space/enter to continue
1851→        if (ev && ev.type === 'fortune' && (key === ' ' || key === 'Enter')) {
1852→          e.preventDefault();
1853→          advanceFromEvent();
1854→        }
1855→      } else {
1856→        if (key === ' ' || key === 'Enter') {
1857→          e.preventDefault();
1858→          if (checkDeath()) return;
1859→          advanceFromEvent();
1860→        }
1861→      }
1862→      break;
1863→
1864→    case STATES.DEATH:
1865→      if (key === ' ' || key === 'Enter') {
1866→        e.preventDefault();
1867→        resetGame();
1868→        renderTitleScreen();
1869→        renderStatusBar();
1870→      }
1871→      break;
1872→
1873→    case STATES.WIN:
1874→      if (key === ' ' || key === 'Enter') {
1875→        e.preventDefault();
1876→        resetGame();
1877→        renderTitleScreen();
1878→        renderStatusBar();
1879→      }
1880→      break;
1881→  }
1882→});
1883→
1884→// =====================================================================
1885→// ANIMATION LOOP + TECH DEBT DRAIN
1886→// =====================================================================
1887→var lastTime = 0;
1888→var drainAccumulator = 0;
1889→var DRAIN_INTERVAL = 3000; // drain 1 HP every 3 seconds
1890→var techDebtDeath = false;
1891→
1892→function gameLoop(timestamp) {
1893→  var dt = timestamp - lastTime;
1894→  lastTime = timestamp;
1895→
1896→  // Clamp dt to avoid huge jumps
1897→  if (dt > 100) dt = 16;
1898→
1899→  if (gameState === STATES.TRAVEL) {
1900→    scrollX += dt * 0.03;
1901→    wagonWheelAngle += dt * 0.004;
1902→  } else if (gameState === STATES.TITLE) {
1903→    scrollX += dt * 0.01;
1904→  } else {
1905→    // Gentle idle scroll
1906→    scrollX += dt * 0.002;
1907→  }
1908→
1909→  // Tech debt drain: HP ticks down during active gameplay (disabled for Ralph Wiggum)
1910→  var isForgiving = PROFESSIONS[difficulty] && PROFESSIONS[difficulty].forgiving;
1911→  var isActive = gameState === STATES.STOP || gameState === STATES.EVENT || gameState === STATES.RIVER;
1912→  if (isActive && !deathPending && !isForgiving) {
1913→    drainAccumulator += dt;
1914→    while (drainAccumulator >= DRAIN_INTERVAL) {
1915→      drainAccumulator -= DRAIN_INTERVAL;
1916→      health--;
1917→      renderStatusBar();
1918→      if (health <= 0) {
1919→        techDebtDeath = true;
1920→        enterDeath();
1921→        break;
1922→      }
1923→    }
1924→  }
1925→
1926→  renderCanvas(timestamp);
1927→  animFrame = requestAnimationFrame(gameLoop);
1928→}
1929→
1930→// =====================================================================
1931→// INITIALIZATION
1932→// =====================================================================
1933→resetGame();
1934→renderTitleScreen();
1935→renderStatusBar();
1936→updateMusicIndicator();
1937→animFrame = requestAnimationFrame(gameLoop);
1938→</script>
